"use client";

type TimelinePipProps = {
  className?: string;
  team?: "ally" | "enemy";
  active?: boolean;
  dead?: boolean;
};

export function TimelinePip({
  className,
  team = "ally",
  active = false,
  dead = false,
}: TimelinePipProps) {
  const fill =
    team === "ally"
      ? "var(--color-dofus-team-blue, #0000ff)"
      : "var(--color-dofus-team-red, #ff0000)";
  const opacity = dead ? 0.3 : 1;
  return (
    <svg
      overflow="visible"
      viewBox="0 0 24 28"
      xmlns="http://www.w3.org/2000/svg"
      width="24px"
      height="28px"
      className={className}
      shapeRendering="geometricPrecision"
    >
      <title>Turn slot</title>
      <g opacity={opacity}>
        <rect
          x="1.5"
          y="1.5"
          width="21"
          height="25"
          rx="2"
          fill={fill}
          stroke={active ? "#ffffff" : "#402b15"}
          strokeWidth={active ? 2 : 1}
        />
        {dead && (
          <path
            stroke="#ffffff"
            strokeWidth="2"
            strokeLinecap="round"
            d="M6 6 L18 22 M18 6 L6 22"
          />
        )}
      </g>
    </svg>
  );
}

"use client";

export function HP({ className }: { className?: string }) {
  return (
    <svg
      overflow="visible"
      viewBox="0 0 16 16"
      xmlns="http://www.w3.org/2000/svg"
      width="16px"
      height="16px"
      className={className}
      shapeRendering="geometricPrecision"
    >
      <title>Hit points</title>
      <path
        d="M8 14 Q2 10 2 6 Q2 3 5 3 Q7 3 8 5 Q9 3 11 3 Q14 3 14 6 Q14 10 8 14 Z"
        fill="var(--color-dofus-hp-red, #c81414)"
        stroke="#ffffff"
        strokeWidth="1"
        strokeLinejoin="round"
      />
    </svg>
  );
}

"use client";

type SpellSlotFrameProps = {
  className?: string;
  state?: "ready" | "disabled" | "selected" | "cooldown";
};

export function SpellSlotFrame({
  className,
  state = "ready",
}: SpellSlotFrameProps) {
  const borderColor =
    state === "selected"
      ? "#ffd44a"
      : state === "disabled"
        ? "#5a5245"
        : "#d5cfaa";
  const borderWidth = state === "selected" ? 2 : 1.5;
  return (
    <svg
      overflow="visible"
      viewBox="0 0 40 40"
      xmlns="http://www.w3.org/2000/svg"
      width="40px"
      height="40px"
      className={className}
      shapeRendering="geometricPrecision"
    >
      <title>Spell slot</title>
      <rect
        x={borderWidth / 2}
        y={borderWidth / 2}
        width={40 - borderWidth}
        height={40 - borderWidth}
        rx="3"
        fill="#1a1610"
        stroke={borderColor}
        strokeWidth={borderWidth}
      />
    </svg>
  );
}
